SELECT id, task_name AS taskName, task_code AS taskCode, source_url AS sourceUrl, source_type AS sourceType, crawl_rule AS crawlRule, priority, cron_expression AS cronExpression, max_retry AS maxRetry, retry_delay AS retryDelay, timeout_seconds AS timeoutSeconds, status, last_run_time AS lastRunTime, next_run_time AS nextRunTime, total_runs AS totalRuns, success_runs AS successRuns, fail_runs AS failRuns, description, enabled, created_by AS createdBy, created_at AS createdAt, updated_at AS updatedAt FROM crawl_tasks
AND status = #{status}
AND priority = #{priority}
ORDER BY FIELD(priority, 10, 5, 1), id DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM crawl_tasks


        AND status = #{status}


        AND priority = #{priority}
